    "Glass",
    "Doors Windows",
    "Roof",
    "Deck",
    "Courtyard",
    "Landscape",
    "Furniture",
    "Utilities",
    "Plantation",
    "Lighting",
    "Annotations"
  ]
  tags.each { |t| layers.add(t) }
  
  # ----------------------------------------------------
  # STEP 3: CREATE PREMIUM MATERIALS PALETTE (HSL-Tailored)
  # ----------------------------------------------------
  materials = model.materials
  
  def add_material(materials, name, r, g, b, alpha = 1.0)
    mat = materials[name] || materials.add(name)
    mat.color = Sketchup::Color.new(r, g, b)
    mat.alpha = alpha
    mat
  end
  
  m_charcoal_metal = add_material(materials, "Matte Charcoal Metal", 38, 43, 49) # Deep luxurious structural framing
  m_bamboo         = add_material(materials, "Bamboo Cladding", 195, 163, 115)   # Natural warm bamboo tone
