  # Helper to draw a frame and glass for doors/windows
  def draw_opening_frame(entities, x1, y1, x2, y2, z_bottom, z_top, thickness, type)
    frame_thick = 40 # Slim profile minimal framing
    x_min, x_max = [x1, x2].minmax
    y_min, y_max = [y1, y2].minmax
    
    frame_group = entities.add_group
    frame_group.name = type == :door ? "Door Frame" : "Window Frame"
    
    model = Sketchup.active_model
    bronze_mat = model.materials["Anodized Bronze Frame"]
    glass_mat = model.materials["LowE Blue Glass"]
    fe = frame_group.entities
    
    if y1 == y2
      y = y1
      # Top/bottom rails
      draw_box(fe, x_min, y - frame_thick/2.0, z_bottom, x_max, y + frame_thick/2.0, z_bottom + frame_thick, bronze_mat, "Doors Windows")
      draw_box(fe, x_min, y - frame_thick/2.0, z_top - frame_thick, x_max, y + frame_thick/2.0, z_top, bronze_mat, "Doors Windows")
      # Left/right stiles
