        draw_box(fe, x_min + frame_thick, y - 10, z_bottom + frame_thick, mid_x, y + 10, z_top - frame_thick, glass_mat, "Glass")
        draw_box(fe, mid_x, y - 20, z_bottom + frame_thick, x_max - frame_thick, y, z_top - frame_thick, glass_mat, "Glass")
        # Center slide divider column
        draw_box(fe, mid_x - 20, y - 25, z_bottom + frame_thick, mid_x + 20, y + 25, z_top - frame_thick, bronze_mat, "Doors Windows")
      end
    else
      x = x1
