        op_start = x_min + op[:start]
        op_end = op_start + op[:width]
        
        if op_start > current_x
          draw_box(entities, current_x, y - thickness/2.0, z_bottom, op_start, y + thickness/2.0, z_top, material_ext, "Walls")
          # FINE TIMBER SLATS OVERLAY FOR SHADOW TEXTURE (40mm wide, 10mm deep, spaced 150mm)
