            slat_x = current_x + k * slat_spacing
            draw_box(entities, slat_x - 20, y - thickness/2.0 - 10, z_bottom, slat_x + 20, y - thickness/2.0, z_top, Sketchup.active_model.materials["Teak Wood"], "Walls")
