  def draw_premium_container(entities, x_sw, y_sw, length, width, height, m_metal, m_wood, tag_name, name)
    c_group = entities.add_group
    c_group.name = name
    ce = c_group.entities
    
    # floor slab
    draw_box(ce, x_sw, y_sw, 450, x_sw + length, y_sw + width, 550, m_wood, tag_name)
    # roof slab
    draw_box(ce, x_sw, y_sw, 450 + height - 150, x_sw + length, y_sw + width, 450 + height, m_metal, tag_name)
    
    # Charcoal structural modular framing (headers and columns)
    cw = 150
    draw_box(ce, x_sw, y_sw, 550, x_sw + cw, y_sw + cw, 450 + height - 150, m_metal, tag_name)
    draw_box(ce, x_sw + length - cw, y_sw, 550, x_sw + length, y_sw + cw, 450 + height - 150, m_metal, tag_name)
    draw_box(ce, x_sw, y_sw + width - cw, 550, x_sw + cw, y_sw + width, 450 + height - 150, m_metal, tag_name)
    draw_box(ce, x_sw + length - cw, y_sw + width - cw, 550, x_sw + length, y_sw + width, 450 + height - 150, m_metal, tag_name)
    
    # Structural headers running along bottom and top edges
    draw_box(ce, x_sw, y_sw, 450, x_sw + length, y_sw + cw, 550, m_metal, tag_name)
    draw_box(ce, x_sw, y_sw + width - cw, 450, x_sw + length, y_sw + width, 550, m_metal, tag_name)
    draw_box(ce, x_sw, y_sw, 450 + height - 150, x_sw + length, y_sw + cw, 450 + height, m_metal, tag_name)
    draw_box(ce, x_sw, y_sw + width - cw, 450 + height - 150, x_sw + length, y_sw + width, 450 + height, m_metal, tag_name)
    
    tag = Sketchup.active_model.layers[tag_name]
    c_group.layer = tag if tag
    c_group
  end
  
